using UnityEngine;

/// <summary>
/// Encaminha os botões do player para os módulos de habilidade da forma actual:
///
/// - Botão de HABILIDADE: PrimaryAbility da forma (Dash, Sprint, Charge, Roll,
///   Camo, Sonar, TonguePull, Egg, HeavyStrike, Roar, ShellGuard, NightVision).
///   NOTA (P4): Climb saiu daqui — escalar é botão de INTERAGIR + cima
///   (paredes) ou apertar Interagir dentro de cordas/escadas.
///   NOTA (Tarefa #5): Glide também saiu daqui — agora é genérico (qualquer
///   forma com canGlide) e activado pelo botão de SALTAR enquanto no ar (ver
///   OnJumpPressedAirborne/OnJumpReleasedAirborne). Isto liberta o botão de
///   Habilidade da Coruja para NightVision (PrimaryAbility.NightVision).
/// - Botão de SALTAR (no ar): Glide genérico — ver OnJumpPressedAirborne.
/// - Botão de ATAQUE: PlayerAttack (garras/mordida básica, dano da ficha) ou,
///   se estiver a carregar um objecto, atira-o (GrabThrowAbility).
/// - Botão de INTERAGIR (correcção): NÃO há botão de "agarrar" dedicado.
///   Agarrar objectos (GrabThrowAbility) e puxar (PullAbility) acontecem
///   automaticamente enquanto o jogador segura Interagir (lidos directamente
///   pelos seus próprios Update — ver esses scripts). Este router só trata o
///   TOQUE de Interagir: largar um objecto carregado, ou agarrar/largar
///   cordas/escadas (toggle). Diálogo com NPCs continua a subscrever
///   InteractPressed directamente (NpcController/NpcDialogueBalloon).
///
/// (CrawlAbility não entra aqui: é passiva, não usa botão.)
/// </summary>
public class AbilityRouter : MonoBehaviour
{
    [SerializeField] private FormSwitcher forms;
    [SerializeField] private PlayerMotor2D motor;

    [Header("Modules (auto-detectados se vazios)")]
    [SerializeField] private DashAbility dash;
    [SerializeField] private ChargeAbility charge;
    [SerializeField] private RollAbility roll;
    [SerializeField] private GlideAbility glide;
    [SerializeField] private ClimbAbility climb;
    [SerializeField] private SprintAbility sprint;
    [SerializeField] private CamoAbility camo;
    [SerializeField] private SonarAbility sonar;
    [SerializeField] private TonguePullAbility tongue;
    [SerializeField] private EggAbility egg;
    [SerializeField] private HeavyStrikeAbility heavyStrike;
    [SerializeField] private RoarAbility roar;
    [SerializeField] private ShellGuardAbility shellGuard;
    [SerializeField] private GrabThrowAbility grabThrow;
    [SerializeField] private PullAbility pull;
    [SerializeField] private SwingAbility swing;
    [SerializeField] private NightVisionAbility nightVision;
    [SerializeField] private PlayerAttack playerAttack;

    // Tarefa #7 — habilidades secundárias por animal.
    [SerializeField] private PounceAbility pounce;
    [SerializeField] private SpinAttackAbility spinAttack;
    [SerializeField] private IceBrakeAbility iceBrake;

    private PlayerInputRouter _input;

    /// <summary>
    /// Todas as habilidades "com estado" do player que implementam IAbility
    /// (Climb, Dash, ShellGuard, Swing, TonguePull, GrabThrow, ...) — usado por
    /// <see cref="CancelAll"/> (item 8 da auditoria) para as interromper em bloco.
    /// </summary>
    private IAbility[] _cancellables;

    private void Awake()
    {
        _cancellables = GetComponents<IAbility>();

        if (_input == null) _input = GetComponent<PlayerInputRouter>();
        if (forms == null) forms = GetComponent<FormSwitcher>();
        if (motor == null) motor = GetComponent<PlayerMotor2D>();
        if (dash == null) dash = GetComponent<DashAbility>();
        if (charge == null) charge = GetComponent<ChargeAbility>();
        if (roll == null) roll = GetComponent<RollAbility>();
        if (glide == null) glide = GetComponent<GlideAbility>();
        if (climb == null) climb = GetComponent<ClimbAbility>();
        if (sprint == null) sprint = GetComponent<SprintAbility>();
        if (camo == null) camo = GetComponent<CamoAbility>();
        if (sonar == null) sonar = GetComponent<SonarAbility>();
        if (tongue == null) tongue = GetComponent<TonguePullAbility>();
        if (egg == null) egg = GetComponent<EggAbility>();
        if (heavyStrike == null) heavyStrike = GetComponent<HeavyStrikeAbility>();
        if (roar == null) roar = GetComponent<RoarAbility>();
        if (shellGuard == null) shellGuard = GetComponent<ShellGuardAbility>();
        if (grabThrow == null) grabThrow = GetComponent<GrabThrowAbility>();
        if (pull == null) pull = GetComponent<PullAbility>();
        if (swing == null) swing = GetComponent<SwingAbility>();
        if (nightVision == null) nightVision = GetComponent<NightVisionAbility>();
        if (playerAttack == null) playerAttack = GetComponent<PlayerAttack>();
        if (pounce == null) pounce = GetComponent<PounceAbility>();
        if (spinAttack == null) spinAttack = GetComponent<SpinAttackAbility>();
        if (iceBrake == null) iceBrake = GetComponent<IceBrakeAbility>();
    }

    // ==================== Botão de HABILIDADE ====================

    public void OnAbilityPressed()
    {
        var form = forms != null ? forms.CurrentForm : null;
        if (form == null) return;

        if (ChallengeManager.Instance != null && ChallengeManager.Instance.IsAbilityRestricted(form.primaryAbility)) return;

        switch (form.primaryAbility)
        {
            case PrimaryAbility.Dash:
                if (dash != null) dash.TryDash();
                break;

            case PrimaryAbility.Charge:
                if (charge != null) charge.StartCharge();
                break;

            case PrimaryAbility.Roll:
                if (roll != null) roll.TryRoll();
                break;

            // Glide: REMOVIDO do botão de habilidade (Tarefa #5) — agora é
            // genérico (qualquer forma com canGlide) e activado pelo botão de
            // SALTAR enquanto no ar — ver OnJumpPressedAirborne/StopGlide
            // abaixo. 'PrimaryAbility.Glide' fica obsoleto (mantido só para
            // não partir assets antigos), tal como Climb.

            case PrimaryAbility.Sprint:
                if (sprint != null) sprint.StartSprint();
                break;

            case PrimaryAbility.Camo:
                if (camo != null) camo.TryCamo();
                break;

            case PrimaryAbility.Sonar:
                if (sonar != null) sonar.TryPing();
                break;

            case PrimaryAbility.TonguePull:
                if (tongue != null) tongue.TryPull();
                break;

            case PrimaryAbility.Egg:
                if (egg != null) egg.TryLayEgg();
                break;

            case PrimaryAbility.HeavyStrike:
                if (heavyStrike != null) heavyStrike.TryStrike();
                break;

            case PrimaryAbility.Roar:
                if (roar != null) roar.TryRoar();
                break;

            case PrimaryAbility.ShellGuard:
                if (shellGuard != null) shellGuard.StartGuard();
                break;

            case PrimaryAbility.NightVision:
                if (nightVision != null) nightVision.Toggle();
                break;

            case PrimaryAbility.Pounce:
                if (pounce != null) pounce.TryPounce();
                break;

            case PrimaryAbility.SpinAttack:
                if (spinAttack != null) spinAttack.TrySpin();
                break;

            case PrimaryAbility.IceBrake:
                if (iceBrake != null) iceBrake.TryBrake();
                break;

            // Climb: REMOVIDO do botão de habilidade (P4) — agora é via
            // Interagir (segurar+cima em paredes, ou toque em cordas/escadas
            // — ver OnInteractPressed/ClimbAbility).

            default:
                break;
        }
    }

    public void OnAbilityReleased()
    {
        var form = forms != null ? forms.CurrentForm : null;
        if (form == null) return;

        switch (form.primaryAbility)
        {
            case PrimaryAbility.Charge:
                if (charge != null) charge.ReleaseCharge();
                break;

            // Glide: ver comentário em OnAbilityPressed — agora termina via
            // OnJumpReleasedAirborne, não pelo botão de habilidade.

            case PrimaryAbility.Sprint:
                if (sprint != null) sprint.StopSprint();
                break;

            case PrimaryAbility.ShellGuard:
                if (shellGuard != null) shellGuard.StopGuard();
                break;
        }
    }

    // ==================== Botão de SALTAR (no ar) — Glide genérico ====================

    /// <summary>
    /// Tarefa #5: Planar (Glide) deixa de depender de 'primaryAbility == Glide'
    /// (exclusivo da Coruja) e passa a estar disponível, de forma genérica,
    /// para QUALQUER forma com 'canGlide' — activado ao apertar o botão de
    /// SALTAR de novo enquanto no ar (em vez de salto extra). Chamado pelo
    /// PlayerController em paralelo com PlayerMotor2D.QueueJumpPressed.
    ///
    /// PlayerMotor2D.PrepareJumpRequests() já não consome 'jumpsLeft' para
    /// formas com canGlide (ver 'form.canGlide' nesse método) — o botão de
    /// salto no ar é reservado para o glide nessas formas.
    /// </summary>
    public void OnJumpPressedAirborne()
    {
        var form = forms != null ? forms.CurrentForm : null;
        if (form == null || !form.canGlide || glide == null) return;

        if (ChallengeManager.Instance != null && ChallengeManager.Instance.IsAbilityRestricted(PrimaryAbility.Glide)) return;

        if (motor == null || motor.IsGrounded) return;

        glide.StartGlide();
    }

    /// <summary>
    /// Soltar o botão de SALTAR termina o glide (queda livre normal) — espelha
    /// o antigo comportamento do botão de Habilidade para PrimaryAbility.Glide.
    /// StopGlide() já é no-op se não estiver a planar.
    /// </summary>
    public void OnJumpReleasedAirborne()
    {
        if (glide != null) glide.StopGlide();
    }

    // ==================== Botão de ATAQUE ====================

    public void OnAttackPressed()
    {
        // A carregar um objecto: o ataque atira-o (Babuíno — arremesso sem dano).
        if (grabThrow != null && grabThrow.IsCarrying)
        {
            grabThrow.ThrowOrDrop();
            return;
        }

        // Atacar quebra a camuflagem.
        if (camo != null && camo.IsCamoActive && camo.breakOnAttack)
            camo.BreakCamo();

        if (playerAttack != null) playerAttack.TryAttack();
    }

    // ==================== Botão de INTERAGIR (toque) ====================

    /// <summary>
    /// Chamado pelo PlayerController em InteractPressed (toque). Agarrar
    /// objectos por toque/proximidade já é tratado em GrabThrowAbility.Update
    /// (segurar Interagir), e largar é tratado em GrabThrowAbility ao SOLTAR
    /// Interagir (InteractReleased); aqui tratamos as acções de TOQUE que
    /// restam: agarrar/largar cordas/escadas, e agarrar/soltar cipós de
    /// balanço (P8 — só se Climb não consumiu o toque).
    /// </summary>
    public void OnInteractPressed()
    {
        // Enquanto carrega um objecto, o toque de Interagir não faz nada aqui
        // (largar é ao soltar — ver GrabThrowAbility.HandleInteractReleased).
        if (grabThrow != null && grabThrow.IsCarrying) return;

        // Mitigação do conflito de InteractPressed (pedido "InteractionManager"):
        // se outro sistema já reagiu a este toque (ex.: diálogo activo, NPC,
        // SafeHaven), não agarramos/largamos cordas/cipós no mesmo toque.
        if (_input != null && _input.InteractConsumed) return;

        // Cordas/escadas: apertar enquanto estiver dentro agarra/larga (toggle).
        if (climb != null && climb.TryToggleVineAttach())
        {
            if (_input != null) _input.InteractConsumed = true;
            return;
        }

        // Cipós de balanço (P8): apertar enquanto estiver dentro agarra/larga (toggle).
        if (swing != null && swing.TryToggleSwingAttach())
        {
            if (_input != null) _input.InteractConsumed = true;
        }
    }

    // ==================== Cancelamento centralizado (Item 8) ====================

    /// <summary>
    /// Interrompe TODAS as habilidades "com estado" actualmente activas
    /// (Climb, Dash, ShellGuard, Swing, TonguePull, GrabThrow, ...), cada uma
    /// chamando o seu próprio Cancel (que já restaura
    /// movimento/gravidade/velocidade — ver StopClimb/StopDashIfRunning/
    /// StopGuard/StopSwing/StopPull/Drop).
    ///
    /// Chamado sempre que o player entra num estado que não deve coexistir com
    /// uma habilidade activa: transformar (FormSwitcher.ApplyForm), morrer
    /// (PlayerDeathHandler), abrir diálogo/cutscene/menu, ficar preso numa
    /// armadilha, sair da água, ou trocar de cena.
    /// </summary>
    public void CancelAll(AbilityCancelReason reason)
    {
        if (_cancellables == null) return;

        foreach (var ability in _cancellables)
            ability?.Cancel(reason);
    }

    // ==================== HUD (Tarefa #32) ====================

    /// <summary>
    /// Devolve o módulo da habilidade primária da forma actual como
    /// <see cref="IActiveAbility"/> (Tarefa #34) — usado pelo HUD para mostrar
    /// cooldown, estado activo e disponibilidade do botão de Habilidade de
    /// forma uniforme. TODAS as habilidades activas implementam
    /// IActiveAbility (ver IActiveAbility.cs); para as que não têm cooldown
    /// próprio, <see cref="IActiveAbility.CooldownDuration"/> é 0 e o HUD não
    /// mostra qualquer indicador de cooldown (mas pode ainda usar
    /// CanActivate/IsActive, se aplicável).
    /// </summary>
    public IActiveAbility GetPrimaryAbilityCooldownSource()
    {
        var form = forms != null ? forms.CurrentForm : null;
        if (form == null) return null;

        switch (form.primaryAbility)
        {
            case PrimaryAbility.Dash: return dash as IActiveAbility;
            case PrimaryAbility.Charge: return charge as IActiveAbility;
            case PrimaryAbility.Roll: return roll as IActiveAbility;
            case PrimaryAbility.Glide: return glide as IActiveAbility;
            case PrimaryAbility.Sprint: return sprint as IActiveAbility;
            case PrimaryAbility.Camo: return camo as IActiveAbility;
            case PrimaryAbility.Sonar: return sonar as IActiveAbility;
            case PrimaryAbility.TonguePull: return tongue as IActiveAbility;
            case PrimaryAbility.Egg: return egg as IActiveAbility;
            case PrimaryAbility.HeavyStrike: return heavyStrike as IActiveAbility;
            case PrimaryAbility.Roar: return roar as IActiveAbility;
            case PrimaryAbility.ShellGuard: return shellGuard as IActiveAbility;
            case PrimaryAbility.NightVision: return nightVision as IActiveAbility;
            case PrimaryAbility.Pounce: return pounce as IActiveAbility;
            case PrimaryAbility.SpinAttack: return spinAttack as IActiveAbility;
            case PrimaryAbility.IceBrake: return iceBrake as IActiveAbility;
            default: return null;
        }
    }
}
